  ('locality-6e2f88c7-moex-00248', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依實務見解，關於緊急命令，下列敘述何者正確？', '["總統僅於應付重大財政危機時，得經行政院會議之議決，發布緊急命令", "總統發布緊急命令之前，應徵詢立法院院長之意見", "緊急命令之內容應力求周延，以不得再授權為補充規定即可逕予執行為原則", "緊急命令得永久變更或取代相關法律之效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00249', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '關於公益原則，下列敘述何者正確？', '["主管機關發現核准之生活扶助處分，確屬錯誤，即得依公益原則，無條件撤銷原處分", "主管機關基於避免法定傳染病快速蔓延之重大公益，得將與患者有過接觸之人，令入指定之處 所施行適當期間之必要強制隔離處置", "主管機關出於增進交通流暢度等公益考量，得不經相關程序，徵收民眾之土地，拓寬道路", "主管機關本於維持治安之公益要求，得依職權訂定行政規則禁止製造、運輸、販售、攜帶與公 開陳列類似真槍之玩具槍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00250', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '關於人民與國家之法律關係，下列敘述何者錯誤？', '["依目前行政法院見解，公立學校教師與學校間之法律關係為行政契約", "全民健康保險特約醫事機構與衛生福利部中央健康保險署簽訂之特約，依司法院解釋係屬行政 契約", "退除役軍職人員與臺灣銀行間優惠存款利息爭議，依司法院解釋應由行政法院審理", "私立大學學生遭學校撤銷學籍爭議，依司法院解釋應由行政法院審理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00251', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-111-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依地方制度法之規定，有關自治條例，下列敘述何者錯誤？', '["經地方立法機關議決後，均須送請行政院核定", "得對違反地方自治事項之行政義務者處以罰鍰", "地方自治團體之組織，應以自治條例規定之", "上級政府認定其規定與中央法令牴觸者，得予以函告無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:48+00:00", "source_pdf_sha1": "502a37da06fb", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "317", "s": "0710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
